class Solution:
    def maxSumDistinctTriplet(self, x, y):
        n = len(x)
        best = -1
        for i in range(n):
            for j in range(i + 1, n):
                for k in range(j + 1, n):
                    if x[i] != x[j] and x[j] != x[k] and x[i] != x[k]:
                        best = max(best, y[i] + y[j] + y[k])
        return best

