class Solution:
    def maxSumDistinctTriplet(self, x, y):
        best = {}
        for xi, yi in zip(x, y):
            if xi not in best or yi > best[xi]:
                best[xi] = yi
        vals = sorted(best.values(), reverse=True)
        if len(vals) < 3:
            return -1
        return vals[0] + vals[1] + vals[2]

