var maxSumDistinctTriplet = function(x, y) {
    const best = new Map();
    for (let i = 0; i < x.length; i++) {
        const xi = x[i], yi = y[i];
        if (!best.has(xi) || yi > best.get(xi)) best.set(xi, yi);
    }
    const vals = [...best.values()].sort((a, b) => b - a);
    if (vals.length < 3) return -1;
    return vals[0] + vals[1] + vals[2];
};
